function calculate({ diplomatic_relations_score, economic_vulnerability_score, military_aggression_index, treaty_compliance_breach_score, internal_political_instability_score, resource_contention_index, cyber_espionage_threat_index }) {

    // Input validation and clamping to ensure scores are within 0-10. This is a defensive measure
    // as the UI inputs should already enforce this range.
    const ensureRange = (value) => Math.min(10, Math.max(0, value));

    const drs = ensureRange(diplomatic_relations_score);
    const evs = ensureRange(economic_vulnerability_score);
    const mai = ensureRange(military_aggression_index);
    const tcbs = ensureRange(treaty_compliance_breach_score);
    const ipis = ensureRange(internal_political_instability_score);
    const rci = ensureRange(resource_contention_index);
    const ceti = ensureRange(cyber_espionage_threat_index);

    // Define weights for each factor. These weights sum to 10, meaning a maximum possible
    // contribution of 10 from each factor (if scored 10) results in a max total score of 100.
    // Higher weights indicate greater influence on overall geopolitical risk.
    const W_diplomacy = 1.5; // Lower diplomatic score (hostility) -> higher risk
    const W_economy = 1.5;   // Higher economic vulnerability -> higher risk
    const W_military = 2.0;  // Higher military aggression -> higher risk
    const W_treaty = 1.0;    // Higher treaty breach score -> higher risk
    const W_internal = 2.0;  // Higher internal instability -> higher risk
    const W_resources = 1.0; // Higher resource contention -> higher risk
    const W_cyber = 1.0;     // Higher cyber threat -> higher risk

    // Calculate the weighted risk contributions.
    // The 'Diplomatic Relations Score' is inverted (10 - drs) because a high input score
    // signifies good relations (low risk), so its contribution to total risk should be low.
    let geopolitical_risk_score = 
        (10 - drs) * W_diplomacy +
        evs * W_economy +
        mai * W_military +
        tcbs * W_treaty +
        ipis * W_internal +
        rci * W_resources +
        ceti * W_cyber;

    // Final clamping of the score to ensure it strictly remains within the 0-100 range,
    // handling any potential minor floating-point inaccuracies.
    geopolitical_risk_score = Math.min(100, Math.max(0, geopolitical_risk_score));

    let risk_category;
    if (geopolitical_risk_score <= 20) {
        risk_category = 'Very Low Risk';
    } else if (geopolitical_risk_score <= 40) {
        risk_category = 'Low Risk';
    } else if (geopolitical_risk_score <= 60) {
        risk_category = 'Moderate Risk';
    } else if (geopolitical_risk_score <= 80) {
        risk_category = 'High Risk';
    } else {
        risk_category = 'Critical Risk';
    }

    return {
        geopolitical_risk_score: parseFloat(geopolitical_risk_score.toFixed(1)),
        risk_category: risk_category
    };
}
